//vip.opstream15.com/share/92b47f497a9c49c386b46a840307c3e1","link_m3u8":"https://vip.opstream15.com/20220612/20413_ef9d87e9/index.m3u8"},{"name":"12","slug":"12","filename":"tuoi-tre-muon-mau-thuyet-minh-age-of-youth-thuyet-minh-tap-12","link_embed":"https://vip.opstream15.com/share/b4fddb161c723fe41814b43123ff0f9c","link_m3u8":"https://vip.opstream15.com/20220612/20414_9921f490/index.m3u8"}]}],"time":"65 phút/tập","description":"<p>Một bộ phim kể về tuổi thanh xuân của những cô gái trẻ đầy lạc quan, hài hước, trẻ trung, câu chuyện xoay quanh năm cô gái cùng trọ sống trong một ngôi nhà, Mỗi người có 1 cá tính riêng của mình, về phong cách hẹn hò, gu đàn ông, và học các ngành khác nhau. Bộ phim mô tả cách các cô gái đối phó với một loạt các vấn đề mà phụ nữ hiện đại phải đối mặt, cho dù đó là hẹn hò hay quan hệ tình dục hay các mối quan hệ giữa các cá nhân. Yoon Jin Myung (Han Ye Ri) rất bận rộn lo chuyện tài chính và học tập cho chính mình. Cô bị thiếu ngủ.Jung Ye Eun (Han Seung Yeon) lại là người hết lòng vì bạn trai của cô, cô rất rõ ràng về những gì cô ấy thích hay không thích. Song Ji Won (Park Eun Bin) có một tính cách trẻ trung và rất thích uống rượu.Kang Yi Na (Ryu Hwa Young) lại khá nổi tiếng bởi sự xuất hiện xinh đẹp của mình. Yoo Eun Jae (Park Hye Soo) có tính cách nhút nhát, nhưng cô ấy lại có duyên ngầm độc đáo thu hút với nam giới.</p>","tmdb":{"type":"tv","id":"67014","season":1,"vote_average":7.189,"vote_count":132},"modified":"2022-06-12T18:20:27.000Z"},{"id":"62a6e27d7a956fb5db0dae55","_id":"62a6e27d7a956fb5db0dae55","title":"Bóng Hình Ánh Trăng","origin_name":"Moonlight Shadow","slug":"bong-hinh-anh-trang","year":2021,"type":"single","genre":[{"id":"620a220de0fc277084dfd16d","name":"Tình Cảm","slug":"tinh-cam"},{"id":"620a2238e0fc277084dfd291","name":"Tâm Lý","slug":"tam-ly"}],"country":[{"id":"620a2307e0fc277084dfd726","name":"Nhật Bản","slug":"nhat-ban"}],"lang_key":"Vietsub","episode_current":"Full","quality":"HD","is_4k":false,"is_exclusive":false,"status":"completed","showtimes":"","chieurap":false,"sub_docquyen":false,"episodes":[{"server_name":"Vietsub #1","is_ai":false,"server_data":[{"name":"Full","slug":"full","filename":"Moonlight.Shadow.2021.JAPANESE.1080p.WEBRip.x264-VXT","link_embed":"https://vip.opstream14.com/share/d45959550312221e15fde04690b18acd","link_m3u8":"https://vip.opstream14.com/20220613/14346_be64f79c/index.m3u8"}]}],"time":"93 phút","description":"<p>Hitoshi gặp Satsuki vào ban đêm trên bờ sông, sau khi nghe thấy tiếng chuông nhỏ. Đó là tình yêu sét đánh, và cả hai phải lòng nhau. Ngay sau đó, anh giới thiệu cô với anh trai của mình, Hiiragi, một thanh niên khá kỳ quặc, có vẻ như mắc chứng ngủ rũ và thích nấu ăn cho mọi người vì anh có thể hiểu mọi thứ về họ qua cách họ ăn, và bạn gái của anh, Yumiko, người quan tâm đến điều huyền bí, và đặc biệt là hiện tượng tiêu chuẩn, được cho là, cho phép mọi người triệu tập với người chết. Bốn người họ bắt đầu ngay lập tức, dành toàn bộ thời gian cho nhau, cho đến khi một người bạn của Satsuki sắp chuyển ra nước ngoài đề nghị cho thuê lại căn hộ của cô ấy. Satsuki bắt đầu thảo luận về việc chuyển đến sống cùng với Hitoshi, nhưng vào khoảng thời gian đó, anh và Yumiko bị chết trong một vụ tai nạn xe hơi. Đầy đau buồn, Hiiragi bắt đầu mặc quần áo của Yumiko ở bất cứ đâu anh ấy đến, trong khi Satsuki chìm đắm trong một thói quen rèn luyện thể chất cường độ cao. Tuy nhiên, dường như không có gì có thể giúp ích, cho đến khi cả hai gặp Urara, một phụ nữ mặc áo đen bí ẩn dường như tồn tại ở đâu đó giữa thế giới thực và siêu nhiên, và thu thập các đoạn ghi âm của những người tiết lộ bí mật sâu kín nhất của họ. Bộ phim thực sự bắt đầu với việc Satsuki nói chuyện với cô ấy, trước khi nó quay ngược thời gian để bắt kịp mạch truyện từ đầu. và thu thập các đoạn ghi âm của những người tiết lộ bí mật sâu sắc nhất của họ. Bộ phim thực sự bắt đầu với việc Satsuki nói chuyện với cô ấy, trước khi nó quay ngược thời gian để bắt kịp mạch truyện từ đầu. và thu thập các đoạn ghi âm của những người tiết lộ bí mật sâu sắc nhất của họ. Bộ phim Bóng Hình Ánh Trăng thực sự bắt đầu với việc Satsuki nói chuyện với cô ấy, trước khi nó quay ngược thời gian để bắt kịp mạch truyện từ đầu.&nbsp;</p>","tmdb":{"type":"movie","id":"847335","season":null,"vote_average":6.1,"vote_count":12},"modified":"2022-06-13T10:04:19.000Z"},{"id":"62a6e9eb7a956fb5db0dbca5","_id":"62a6e9eb7a956fb5db0dbca5","title":"Given","origin_name":"Given","slug":"given","year":2017,"type":"hoathinh","genre":[{"id":"620a220de0fc277084dfd16d","name":"Tình Cảm","slug":"tinh-cam"},{"id":"620a22bae0fc277084dfd585","name":"Âm Nhạc","slug":"am-nhac"}],"country":[{"id":"620a2307e0fc277084dfd726","name":"Nhật Bản","slug":"nhat-ban"}],"lang_key":"Vietsub","episode_current":"Hoàn Tất (11/11)","quality":"HD","is_4k":false,"is_exclusive":false,"status":"completed","showtimes":"","chieurap":false,"sub_docquyen":false,"episodes":[{"is_ai":false,"server_name":"Vietsub #1","server_data":[{"name":"01","slug":"01","filename":"Given-tap-01","link_embed":"https://vip.opstream12.com/share/f559cf7514371d4acdaa13b23279b874","link_m3u8":"https://vip.opstream12.com/20220612/19038_0edb7a1e/index.m3u8"},{"name":"02","slug":"02","filename":"Given-tap-02","link_embed":"https://vip.opstream12.com/share/16a8df1b9fc4ed0c3af66ea89567b0bb","link_m3u8":"https://vip.opstream12.com/20220612/19039_14a20bc5/index.m3u8"},{"name":"03","slug":"03","filename":"Given-tap-03","link_embed":"https://vip.opstream12.com/share/86ad2abe9aa87efa03c4bbee3fb005b2","link_m3u8":"https://vip.opstream12.com/20220612/19040_4e4134c9/index.m3u8"},{"name":"04","slug":"04","filename":"Given-tap-04","link_embed":"https://vip.opstream12.com/share/8d297a658bd8918ca2428789005950df","link_m3u8":"https://vip.opstream12.com/20220612/19041_b9584f15/index.m3u8"},{"name":"05","slug":"05","filename":"Given-tap-05","link_embed":"https://vip.opstream12.com/share/6b5d0830f5e349e537c9c4d427f2614f","link_m3u8":"https://vip.opstream12.com/2022061